以下是使用C#实现查找文件夹内所有cpp文件的代码版本：

```
using System;
using System.IO;

namespace FindCPPFiles
{
    class Program
    {
        static void Main(string[] args)
        {
            string folderPath = @"C:\folder\path";  // 文件夹路径
            string[] cppFiles = Directory.GetFiles(folderPath, "*.cpp", SearchOption.AllDirectories);  // 查找所有cpp文件
            foreach (string cppFile in cppFiles)
            {
                Console.WriteLine("File: " + cppFile);  // 输出文件路径
                string fileContent = File.ReadAllText(cppFile);  // 读取文件内容
                Console.WriteLine(fileContent);  // 输出文件内容
            }
        }
    }
}
```

以上程序会列出所给文件夹路径下所有的`.cpp`文件，并输出文件内的内容到控制台。你可以根据需要调整程序细节。

抱歉，我理解有误。以下是使用C#实现查找文件夹内所有cpp文件的版本号：

```
using System;
using System.IO;
using System.Text.RegularExpressions;

namespace FindCPPVersions
{
    class Program
    {
        static void Main(string[] args)
        {
            string folderPath = @"C:\folder\path";  // 文件夹路径
            string[] cppFiles = Directory.GetFiles(folderPath, "*.cpp", SearchOption.AllDirectories);  // 查找所有cpp文件
            foreach (string cppFile in cppFiles)
            {
                Console.WriteLine("File: " + cppFile);  // 输出文件路径
                string fileContent = File.ReadAllText(cppFile);  // 读取文件内容
                string versionPattern = @"\d+\.\d+\.\d+";  // 版本号匹配正则表达式
                Match match = Regex.Match(fileContent, versionPattern);  // 查找版本号
                if (match.Success)
                {
                    Console.WriteLine("Version: " + match.Value);  // 输出版本号
                }
            }
        }
    }
}
```

以上程序会列出所给文件夹路径下所有的`.cpp`文件，并输出文件内的版本号到控制台。你可以根据需要调整程序细节包括版本号的格式和版本号的获取方式。

可以使用C#中的`Workbook`和`Worksheet`对象来进行Excel操作。以下是将查找得到的文件名和版本号输出到Excel的示例代码：

```
using System;
using System.IO;
using System.Text.RegularExpressions;
using Microsoft.Office.Interop.Excel;

namespace FindAndOutputCPPVersions
{
    class Program
    {
        static void Main(string[] args)
        {
            string folderPath = @"C:\folder\path";  // 文件夹路径
            string[] cppFiles = Directory.GetFiles(folderPath, "*.cpp", SearchOption.AllDirectories);  // 查找所有cpp文件

            // 打开Excel应用程序
            var excelApp = new Application { Visible = true };
            var workbook = excelApp.Workbooks.Add();
            var worksheet = (Worksheet)workbook.Sheets[1];

            // 在Excel中输出表头
            worksheet.Cells[1, 1] = "File Name";
            worksheet.Cells[1, 2] = "Version";

            // 在Excel中输出每个cpp文件的版本号
            int row = 2;  // 开始输出数据的行数
            foreach (string cppFile in cppFiles)
            {
                Console.WriteLine("File: " + cppFile);  // 输出文件路径
                string fileContent = File.ReadAllText(cppFile, System.Text.Encoding.Default);  // 读取文件内容
                string versionPattern = @"\d+\.\d+\.\d+";  // 版本号匹配正则表达式
                Match match = Regex.Match(fileContent, versionPattern);  // 查找版本号
                if (match.Success)
                {
                    string version = match.Value;
                    Console.WriteLine("Version: " + version);  // 输出版本号
                    worksheet.Cells[row, 1] = Path.GetFileName(cppFile);  // 输出文件名
                    worksheet.Cells[row, 2] = version;  // 输出版本号
                    row++;
                }
            }

            // 自适应字段宽度
            worksheet.Columns.AutoFit();

            // 保存并关闭Excel文件
            workbook.SaveAs(@"C:\output\file.xlsx");
            workbook.Close(0);
            excelApp.Quit();
        }
    }
}
```

以上程序会将查找得到的文件名和版本号输出到Excel文件中。你可以根据需要调整程序细节，如输出文件路径等。这里使用了Interop.Excel库进行Excel操作，需要先安装Microsoft Office软件。需要注意的是，使用Interop.Excel会须在Excel程序环境下运行，因此需要确保正确的Office环境。
